import React from 'react';
import { escapeHtml } from '../utils/helpers';
import './AppointmentCard.css';

const AppointmentCard = ({ appointment, userRole, onComplete }) => {
  const statusClass = 
    appointment.status === 'completed' ? 'status-completed' :
    appointment.status === 'cancelled' ? 'status-cancelled' : 
    'status-booked';

  return (
    <div className="appointment-card">
      <div className="appointment-header">
        <div className="appointment-date-time">
          <div className="appointment-date">{escapeHtml(appointment.appointment_date)}</div>
          <div className="appointment-time">{escapeHtml(appointment.appointment_time)}</div>
        </div>
        <span className={`status-badge ${statusClass}`}>
          {escapeHtml(appointment.status)}
        </span>
      </div>

      <div className="appointment-body">
        {appointment.doctor_name && (
          <p><strong>Doctor:</strong> {escapeHtml(appointment.doctor_name)}</p>
        )}
        {appointment.patient_name && (
          <p><strong>Patient:</strong> {escapeHtml(appointment.patient_name)}</p>
        )}
      </div>

      {userRole === 'doctor' && appointment.status === 'booked' && onComplete && (
        <div className="appointment-actions">
          <button 
            className="btn btn-complete" 
            onClick={() => onComplete(appointment.id)}
          >
            Mark Completed
          </button>
        </div>
      )}
    </div>
  );
};

export default AppointmentCard;
